package Programs;

public class WapToFindSmallestOfThreeNumbers {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int n1=7; int n2=9; int n3=3;
		
		if(n1<=n1 && n1<=n3) {
			System.out.println(n1);
		}
		else if (n2<=n1 && n2<=n3) {
			System.out.println(n2);
		}
		else {
			System.out.println(n3);
		}

	}

}
